def build_sections(lang: str) -> dict:
    if lang == "zh-tw":
        return _zh_tw()
    base = _en()
    if lang in _LOCALE_OVERRIDES:
        base.update(_LOCALE_OVERRIDES[lang])
    return base


FULL_SECTIONS = {lang: build_sections(lang) for lang in [
    "zh-tw", "ja", "ko", "es", "fr", "de", "pt", "it", "ru", "uk", "pl",
    "nl", "sv", "ro", "ar", "id", "ms", "vi", "th", "tr", "hi", "fa",
]}
